import java.io.*;import java.util.*;class Main{static int abbrLen(int mask,int n){int total=0;boolean skip=false;for(int i=0;i<n;i++)if(((mask>>i)&1)==1){if(skip){total++;skip=false;}total++;}else skip=true;return total+(skip?1:0);}static String build(String t,int mask){StringBuilder out=new StringBuilder();int run=0;for(int i=0;i<t.length();i++)if(((mask>>i)&1)==1){if(run>0){out.append(run);run=0;}out.append(t.charAt(i));}else run++;if(run>0)out.append(run);return out.toString();}static String solve(String t,String[]dict){int n=t.length();ArrayList<Integer>diffs=new ArrayList<>();for(String w:dict){if(w.length()!=n)continue;int d=0;for(int i=0;i<n;i++)if(t.charAt(i)!=w.charAt(i))d|=1<<i;diffs.add(d);}if(diffs.isEmpty())return Integer.toString(n);int best=0,bestLen=n+1;for(int mask=0;mask<(1<<n);mask++){boolean ok=true;for(int d:diffs)if((mask&d)==0){ok=false;break;}if(ok){int l=abbrLen(mask,n);if(l<bestLen){bestLen=l;best=mask;}}}return build(t,best);}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){String target=d[idx++];int m=Integer.parseInt(d[idx++]);String[]dict=new String[m];for(int i=0;i<m;i++)dict[i]=d[idx++];if(tc>0)out.append("\n\n");out.append(solve(target,dict));}System.out.print(out);}}
